def en_uzun_ayni_renk_serisi(renk_kodlari):
    if not renk_kodlari:
        return 0
    en_uzun_seri = 1
    guncel_seri = 1
    for i in range(1, len(renk_kodlari)):
        if renk_kodlari[i] == renk_kodlari[i - 1]:
            guncel_seri += 1
            en_uzun_seri = max(en_uzun_seri, guncel_seri)
        else:
            guncel_seri = 1
    return en_uzun_seri
